import Foundation

enum ValidationError: Error {
    case emptyField(field: String)
    case invalidEmail
    case passwordTooShort(minLength: Int)
    case passwordsDontMatch
}

func validateRegistration(username: String, email: String, password: String, confirmPassword: String) throws {
    guard !username.isEmpty else {
        throw ValidationError.emptyField(field: "Username")
    }
    guard email.contains("@") && email.contains(".") else {
        throw ValidationError.invalidEmail
    }
    guard password.count >= 8 else {
        throw ValidationError.passwordTooShort(minLength: 8)
    }
    guard password == confirmPassword else {
        throw ValidationError.passwordsDontMatch
    }
    print("Registration validated for \(username)")
}

func registerUser(username: String, email: String, password: String, confirm: String) {
    do {
        try validateRegistration(username: username, email: email, password: password, confirmPassword: confirm)
        print("User registered successfully")
    } catch ValidationError.emptyField(let field) {
        print("\(field) cannot be empty")
    } catch ValidationError.invalidEmail {
        print("Please enter a valid email")
    } catch ValidationError.passwordTooShort(let min) {
        print("Password must be at least \(min) characters")
    } catch ValidationError.passwordsDontMatch {
        print("Passwords do not match")
    } catch {
        print("Unexpected error: \(error)")
    }
}

